/**
 * Blur Placeholder Utilities
 *
 * Provides tiny base64 blur data URLs for image placeholders.
 * Used with Next.js Image component's `placeholder="blur"` for better LCP.
 */

/**
 * Get a tiny blur data URL for TMDB poster images.
 * This is a pre-generated 1x1 pixel gray placeholder.
 */
export function getTMDBBlurDataURL(): string {
  // 1x1 pixel gray JPEG - minimal footprint, works for any poster
  return "data:image/jpeg;base64,";
}

/**
 * Get a dark blur data URL for backdrop images.
 * Slightly darker tone to match movie backdrops.
 */
export function getBackdropBlurDataURL(): string {
  // 1x1 pixel darker gray JPEG for backdrops
  return "data:image/jpeg;base64,";
}
